$mes=max(1,min(12,(int)($_GET['mes']??date('n'))));$anio=(int)($_GET['anio']??date('Y'));$uid=(int)($_GET['user_id']??0);$users=[];$r=$conn->query("SELECT id,comercial,username FROM users ORDER BY comercial");if($r)while($x=$r->fetch_assoc())$users[]=$x;$ef=[];$km=[];$where="YEAR(fecha)=? AND MONTH(fecha)=?".($uid>0?' AND user_id=?':'');foreach([['efectivo_gastos','ef'],['kilometrajes','km']] as [$t,$v]){if($conn->query("SHOW TABLES LIKE '$t'")->num_rows){$st=$conn->prepare("SELECT * FROM $t WHERE $where ORDER BY fecha DESC,id DESC");if($uid>0)$st->bind_param('iii',$anio,$mes,$uid);else$st->bind_param('ii',$anio,$mes);$st->execute();$rr=$st->get_result();while($x=$rr->fetch_assoc())${$v}[]=$x;}}
?><!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Efectivo y Kms - Admin</title><link rel="stylesheet" href="../css/admin.css?v=<?php echo APP_VERSION; ?>"></head><body class="admin-body"><div class="admin-wrapper"><header class="admin-header"><div><h1>Efectivo y Kilometraje</h1><p>Consulta general de gastos en efectivo y desplazamientos.</p></div><div class="top-actions"><a class="btn" href="index.php">Panel Admin</a><a class="btn" href="../home.php">Inicio</a><a class="btn" href="../logout.php">Cerrar sesión</a></div></header><section class="panel"><form method="get" class="filters"><div><label>Mes</label><input type="number" name="mes" min="1" max="12" value="<?php echo $mes;?>"></div><div><label>Año</label><input type="number" name="anio" value="<?php echo $anio;?>"></div><div><label>Usuario</label><select name="user_id"><option value="0">Todos</option><?php foreach($users as $u):?><option value="<?php echo (int)$u['id'];?>" <?php echo $uid===(int)$u['id']?'selected':'';?>><?php echo h($u['comercial']);?></option><?php endforeach;?></select></div><button class="btn primary">Filtrar</button></form></section><section class="panel"><h2>Efectivo</h2><div class="table-wrap"><table><thead><tr><th>Fecha</th><th>Comercial</th><th>Motivo</th><th>Importe</th><th>Ticket</th><th>Estado</th></tr></thead><tbody><?php foreach($ef as $x):?><tr><td><?php echo h(formatFechaWeb($x['fecha']));?></td><td><?php echo h($x['comercial']);?></td><td><?php echo h($x['motivo']);?></td><td><?php echo number_format((float)$x['importe'],2,',','.');?> €</td><td><?php echo $x['drive_file_url']?'<a target="_blank" rel="noopener" href="'.h($x['drive_file_url']).'">Ver</a>':'—';?></td><td><?php echo h($x['estado']);?></td></tr><?php endforeach;?></tbody></table></div></section><section class="panel"><h2>Kilometraje</h2><div class="table-wrap"><table><thead><tr><th>Fecha</th><th>Comercial</th><th>Motivo</th><th>Ruta</th><th>Kms</th><th>Importe</th><th>Estado</th></tr></thead><tbody><?php foreach($km as $x):?><tr><td><?php echo h(formatFechaWeb($x['fecha']));?></td><td><?php echo h($x['comercial']);?></td><td><?php echo h($x['motivo']);?></td><td><?php echo h(($x['origen']??'').' → '.($x['destino']??''));?><?php $stops=json_decode((string)($x['paradas_json']??'[]'),true); if(is_array($stops)&&$stops): ?><br><small>Paradas: <?php echo h(implode(' · ',$stops)); ?></small><?php endif; ?><?php if(!empty($x['duracion_minutos'])): ?><br><small><?php echo (int)$x['duracion_minutos']; ?> min</small><?php endif; ?></td><td><?php echo number_format((float)$x['kilometros'],2,',','.');?></td><td><?php echo number_format((float)$x['importe'],2,',','.');?> €</td><td><?php echo h($x['estado']);?></td></tr><?php endforeach;?></tbody></table></div></section></div>
